    // Recursively print only "normal" text nodes (ignoring tags and empty whitespace)
    private static void printTextNodes(Node node) {
        for (Node child : node.childNodes()) {
            if (child instanceof TextNode) {
                String txt = ((TextNode) child).text().trim();
                if (!txt.isEmpty()) {
                    System.out.println(txt);
                }
            } else {
                printTextNodes(child);
            }
        }
    }
    public static void createFileWithContent(String content, String fileName) {
        try{
            FileWriter fw = new FileWriter(fileName);
            fw.write(content);
            fw.close();
        }catch(Exception e){System.out.println(e);}
        System.out.println("Success");
    }
